#!/usr/bin/env bash
# Strict arrange ladder identity gate. Each selected rung is generated by a
# separate SWI process; run_arrange_identity.pl emits the exact /6 result at the
# workload budget and serializes only after the timed search has ended, then
# this script hashes the complete framed row.

set -uo pipefail
cd "$(dirname "$0")/.." || exit 2

manifest="benchmarks/arrange_identity.sha256"
workloads="benchmarks/workloads.pl"
runner="benchmarks/run_arrange_identity.pl"
heavy=0
record=0

for arg in "$@"; do
    case "$arg" in
        --heavy) heavy=1 ;;
        --record) record=1 ;;
        *) echo "check_arrange_identity: unknown option $arg" >&2; exit 2 ;;
    esac
done
if [ "$record" -eq 1 ] && [ "$heavy" -ne 1 ]; then
    echo "check_arrange_identity: --record requires --heavy (the committed manifest must be complete)" >&2
    exit 2
fi

rungs="$(swipl -q -l "$workloads" \
    -g 'forall(arrange_workload(F,_,_,_,_,_,T,_,_,_), format("~w\t~w~n",[F,T])), halt' \
    -g 'halt(1)' </dev/null 2>/dev/null)"
if [ -z "$rungs" ]; then
    echo "check_arrange_identity: could not enumerate workloads" >&2
    exit 2
fi

declare -A expected seen known
if [ -f "$manifest" ]; then
    while IFS=$'\t' read -r id digest; do
        [ -z "$id" ] && continue
        expected["$id"]="$digest"
    done <"$manifest"
fi

if [ "$record" -eq 1 ]; then
    tmp_manifest="$(mktemp "${manifest}.tmp.XXXXXX")"
else
    tmp_manifest="$(mktemp)"
fi
out="$(mktemp)"
trap 'rm -f "$tmp_manifest" "$out"' EXIT
status=0

while IFS=$'\t' read -r fixture tier; do
    [ -z "$fixture" ] && continue
    id="${fixture##*/}"
    known["$id"]=1
    if [ "$tier" = heavy ] && [ "$heavy" -ne 1 ]; then
        continue
    fi
    echo "identity ($id): START ($tier)"
    if swipl -q "$runner" -- "$fixture" >"$out"; then
        read -r digest _ < <(sha256sum "$out")
        printf '%s\t%s\n' "$id" "$digest" >>"$tmp_manifest"
        seen["$id"]=1
        if [ "$record" -eq 1 ]; then
            echo "identity ($id): RECORDED $digest"
        elif [ -z "${expected[$id]:-}" ]; then
            echo "identity ($id): NO BASELINE"; status=1
        elif [ "${expected[$id]}" = "$digest" ]; then
            echo "identity ($id): OK $digest"
        else
            echo "identity ($id): MISMATCH (want ${expected[$id]} got $digest)"; status=1
        fi
    else
        echo "identity ($id): RUNNER FAILED"; status=1
    fi
done <<<"$rungs"

if [ "$record" -eq 1 ]; then
    if [ "$status" -eq 0 ] && [ "${#seen[@]}" -eq "${#known[@]}" ] \
       && mv "$tmp_manifest" "$manifest"; then
        echo "IDENTITY: recorded ${#seen[@]} complete rung digest(s) -> $manifest"
        exit 0
    fi
    echo "IDENTITY: record FAILED; $manifest was not changed"
    exit 1
fi

for id in "${!known[@]}"; do
    if [ -z "${expected[$id]:-}" ]; then
        echo "identity ($id): WORKLOAD ABSENT FROM MANIFEST"; status=1
    fi
done
for id in "${!expected[@]}"; do
    if [ -z "${known[$id]:-}" ]; then
        echo "identity ($id): MANIFEST ENTRY ABSENT FROM WORKLOADS"; status=1
    fi
done

if [ "$status" -eq 0 ]; then
    echo "IDENTITY: all selected rung digests match $manifest"
else
    echo "IDENTITY: FAILED"
fi
exit "$status"
